const input = $input.item.json;

if (input.is_mock) {
  return [{ json: input }];
}

const webhookData = $('Receive Scoot webhook').item?.json || {};
const scootData = input;

return [{
  json: {
    ...webhookData,
    ...scootData,
    transcript: scootData.transcript || 'Transcript fetched from Scoot S3 bucket',
    company_name: scootData.name?.replace('Discovery Call - ', '').replace('Sales Call - ', '') || 'Unknown Company',
    rep_email: scootData.user?.emailAddress || 'user@example.com',
    rep_name: scootData.user?.name || 'Sales Rep',
    call_date: scootData.startDateTime?.split('T')[0] || new Date().toISOString().split('T')[0]
  }
}];

