parameters.jsCode:
// Parse and validate Gemini response
const input = $input.item.json;
const previousData = $('Combine call metadata').item.json;

let extracted;

try {
  const aiResponse = input.text || input.content || input.message?.content || '';
  let jsonString = aiResponse;

  if (jsonString.includes('```json')) {
    jsonString = jsonString.replace(/```json\n?/g, '').replace(/```\n?/g, '');
  } else if (jsonString.includes('```')) {
    jsonString = jsonString.replace(/```\n?/g, '');
  }

  extracted = JSON.parse(jsonString.trim());
} catch (error) {
  extracted = {
    budget_confirmed: null,
    budget_amount: null,
    budget_notes: null,
    competitors_mentioned: [],
    objections_raised: [],
    timeline: null,
    decision_maker: null,
    next_steps: [],
    pain_points: [],
    buying_signals: [],
    call_sentiment: 'neutral',
    deal_stage_recommendation: 'Parsing error - review manually',
    extraction_error: error.message
  };
}

const validated = {
  budget_confirmed: typeof extracted.budget_confirmed === 'boolean' ? extracted.budget_confirmed : null,
  budget_amount: typeof extracted.budget_amount === 'number' ? extracted.budget_amount : null,
  budget_notes: typeof extracted.budget_notes === 'string' ? extracted.budget_notes.slice(0, 500) : null,
  competitors_mentioned: Array.isArray(extracted.competitors_mentioned) ? extracted.competitors_mentioned : [],
  objections_raised: Array.isArray(extracted.objections_raised) ? extracted.objections_raised : [],
  timeline: typeof extracted.timeline === 'string' ? extracted.timeline : null,
  decision_maker: typeof extracted.decision_maker === 'string' ? extracted.decision_maker : null,
  next_steps: Array.isArray(extracted.next_steps) ? extracted.next_steps : [],
  pain_points: Array.isArray(extracted.pain_points) ? extracted.pain_points : [],
  buying_signals: Array.isArray(extracted.buying_signals) ? extracted.buying_signals : [],
  call_sentiment: ['positive', 'neutral', 'negative'].includes(extracted.call_sentiment) ? extracted.call_sentiment : 'neutral',
  deal_stage_recommendation: typeof extracted.deal_stage_recommendation === 'string' ? extracted.deal_stage_recommendation : null
};

return [{
  json: {
    call_id: previousData.socialTranscriptionId,
    deal_id: previousData.deal_id || null,
    company_name: previousData.company_name,
    contact_name: previousData.contact_name || null,
    contact_email: previousData.contact_email || null,
    rep_name: previousData.rep_name,
    rep_email: previousData.rep_email,
    call_date: previousData.call_date,
    ...validated,
    extraction_timestamp: new Date().toISOString(),
    extraction_error: extracted.extraction_error || null
  }
}];

// Format data for CRM and email notification
const data = $input.item.json;

const crmUpdate = {
  deal_id: data.deal_id,
  amount: data.budget_amount,
  close_date: data.timeline,
  budget_confirmed__c: data.budget_confirmed,
  budget_notes__c: data.budget_notes,
  competitors__c: data.competitors_mentioned.join(', '),
  objections__c: data.objections_raised.join(' | '),
  decision_maker__c: data.decision_maker,
  next_steps__c: data.next_steps.join(' | '),
  pain_points__c: data.pain_points.join(' | '),
  buying_signals__c: data.buying_signals.join(' | '),
  last_call_sentiment__c: data.call_sentiment,
  stage_recommendation__c: data.deal_stage_recommendation,
  last_call_date__c: data.call_date,
  last_call_id__c: data.call_id
};

const emailSummary = `
═══════════════════════════════════════════════════════════
POST-CALL SUMMARY: ${data.company_name}
═══════════════════════════════════════════════════════════

CALL DETAILS
────────────
Company: ${data.company_name}
Contact: ${data.contact_name || 'N/A'}
Date: ${data.call_date}
Sentiment: ${data.call_sentiment.toUpperCase()}

BUDGET
──────
Confirmed: ${data.budget_confirmed === true ? 'YES' : data.budget_confirmed === false ? 'NO' : 'Not discussed'}
Amount: ${data.budget_amount ? '$' + data.budget_amount.toLocaleString() : 'Not specified'}
Notes: ${data.budget_notes || 'None'}

COMPETITORS MENTIONED
─────────────────────
${data.competitors_mentioned.length > 0 ? data.competitors_mentioned.map(c => '• ' + c).join('\n') : 'None mentioned'}

OBJECTIONS RAISED
─────────────────
${data.objections_raised.length > 0 ? data.objections_raised.map(o => '• ' + o).join('\n') : 'None raised'}

TIMELINE: ${data.timeline || 'Not specified'}
DECISION MAKER: ${data.decision_maker || 'Not identified'}

NEXT STEPS
──────────
${data.next_steps.length > 0 ? data.next_steps.map((s, i) => (i + 1) + '. ' + s).join('\n') : 'None identified'}

PAIN POINTS
───────────
${data.pain_points.length > 0 ? data.pain_points.map(p => '• ' + p).join('\n') : 'None identified'}

BUYING SIGNALS
──────────────
${data.buying_signals.length > 0 ? data.buying_signals.map(b => '✓ ' + b).join('\n') : 'None identified'}

═══════════════════════════════════════════════════════════
RECOMMENDATION: ${data.deal_stage_recommendation || 'No recommendation'}
═══════════════════════════════════════════════════════════
`;

return [{
  json: {
    ...data,
    crm_update: crmUpdate,
    email_summary: emailSummary
  }
}];

// Mock CRM update - replace with HubSpot/Salesforce/Pipedrive node
const data = $input.item.json;

const mockCrmResponse = {
  success: true,
  crm_provider: 'MOCK - Replace with real CRM',
  deal_id: data.crm_update.deal_id || 'deal_' + Date.now(),
  fields_updated: Object.keys(data.crm_update).filter(k => data.crm_update[k] !== null && data.crm_update[k] !== ''),
  timestamp: new Date().toISOString()
};

return [{
  json: {
    ...data,
    crm_response: mockCrmResponse
  }
}];

// Track retry attempts for incomplete transcripts
const data = $input.item.json;
const currentRetryCount = data.retry_count || 0;
const maxRetries = 6;

return [{
  json: {
    ...data,
    retry_count: currentRetryCount + 1,
    max_retries: maxRetries,
    can_retry: currentRetryCount < maxRetries && data.status === 'PROCESSING'
  }
}];

// Prepare data for retry request
const data = $input.item.json;

return [{
  json: {
    socialTranscriptionId: data.socialTranscriptionId,
    retry_count: data.retry_count,
    original_webhook_data: data.original_webhook_data || data
  }
}];

// Log failure after max retries exceeded
const data = $input.item.json;

const failureReason = data.status === 'FAILED' 
  ? 'Transcription failed in Scoot' 
  : `Max retries exceeded - still processing after ${data.max_retries} hours`;

return [{
  json: {
    status: 'ABANDONED',
    socialTranscriptionId: data.socialTranscriptionId,
    failure_reason: failureReason,
    retry_attempts: data.retry_count || 0,
    timestamp: new Date().toISOString()
  }
}];
